209	/// Verifies RMW mode compatibility with element type for atomic operations.
210	template <typename OpTy>
211	static inline LogicalResult verifyAtomicRMWMode(OpTy op, AtomicRMWMode mode,
212	                                                Type elementType) {
213	  switch (mode) {
214	  case AtomicRMWMode::AND:
215	  case AtomicRMWMode::OR:
216	  case AtomicRMWMode::XOR:
217	  case AtomicRMWMode::ADD:
218	  case AtomicRMWMode::MAX:
219	  case AtomicRMWMode::MIN:
220	  case AtomicRMWMode::UMAX:
221	  case AtomicRMWMode::UMIN: {
222	    auto integerTy = dyn_cast_or_null<IntegerType>(elementType);
223	    if (!integerTy || (!integerTy.isInteger(32) && !integerTy.isInteger(64)))
224	      return op.emitOpError("'") << stringifyAtomicRMWMode(mode)
225	                                 << "' works only with integers i32 and i64";
226	    break;
227	  }
228	  case AtomicRMWMode::ADDF: {
229	    auto floatTy = dyn_cast_or_null<FloatType>(elementType);
230	    if (!floatTy || (!floatTy.isF32() && !floatTy.isF64() && !floatTy.isF16() &&
231	                     !floatTy.isBF16())) {
232	      return op.emitOpError("'")
233	             << stringifyAtomicRMWMode(mode)
234	             << "' works only with floats f16, bf16, f32, and f64";
235	    }
236	    break;
237	  }
238	  case AtomicRMWMode::XCHG: {
239	    auto integerTy = dyn_cast_or_null<IntegerType>(elementType);
240	    auto floatTy = dyn_cast_or_null<FloatType>(elementType);
241	    if (!integerTy && !floatTy)
242	      return op.emitOpError("'")
243	             << stringifyAtomicRMWMode(mode)
244	             << "' works only with integers or float of 32 or 64 bitwidth";
245	    int64_t bitwidth = elementType.getIntOrFloatBitWidth();
246	    if (bitwidth != 32 && bitwidth != 64)
247	      return op.emitOpError("'")
248	             << stringifyAtomicRMWMode(mode)
249	             << "' works only with integers or float of 32 or 64 bitwidth";
250	  }
251	  }
252	  return success();
253	}
