255	/// Verifies memory ordering semantics for atomic operations.
256	template <typename OpTy>
257	static inline LogicalResult
258	verifyAtomicMemoryOrdering(OpTy op, MemoryOrderingSemantics semantics) {
259	  if (semantics != MemoryOrderingSemantics::RELAXED &&
260	      semantics != MemoryOrderingSemantics::ACQUIRE &&
261	      semantics != MemoryOrderingSemantics::RELEASE &&
262	      semantics != MemoryOrderingSemantics::ACQ_REL) {
263	    return op.emitOpError("memory ordering semantics must be one of: "
264	                          "relaxed, acquire, release, acq_rel");
265	  }
266	  return success();
267	}
