1496	LogicalResult AtomicRMWTkoOp::verify() {
1497	  auto ptrType =
1498	      cast<cuda_tile::PointerType>(getPointers().getType().getElementType());
1499	  Type pointeeType = ptrType.getPointeeType();
1500	  Type argElType = getArg().getType().getElementType();
1501	  if (pointeeType != argElType)
1502	    return emitOpError("expected pointee type (")
1503	           << pointeeType << ") to match element type of 'arg' (" << argElType
1504	           << ")";
1505	
1506	  // We cannot add to AllShapesMatch since it is an optional argument.
1507	  auto mask = getMask();
1508	  if (mask && cast<ShapedType>(mask.getType()).getShape() !=
1509	                  cast<ShapedType>(getArg().getType()).getShape())
1510	    return emitOpError(
1511	        "failed to verify that all of {pointers, arg, mask} have same shape");
1512	
1513	  // Check compatibility of RMW mode with element type.
1514	  if (failed(verifyAtomicRMWMode(*this, getMode(), argElType)))
1515	    return failure();
1516	
1517	  // Verify memory ordering semantics.
1518	  if (failed(verifyAtomicMemoryOrdering(*this, getMemoryOrderingSemantics())))
1519	    return failure();
1520	
1521	  return success();
1522	}
