1527	
1528	LogicalResult AtomicRedViewTkoOp::verify() {
1529	  auto viewType = dyn_cast<cuda_tile::TileView>(getView().getType());
1530	  if (!viewType)
1531	    return emitOpError("view operand must be a TileView type");
1532	
1533	  if (isa<cuda_tile::GatherScatterViewType>(getView().getType())) {
1534	    return emitOpError(
1535	        "gather_scatter_view is not supported; use partition_view instead");
1536	  }
1537	
1538	  // Views with padding_value are not supported.
1539	  if (auto pv = dyn_cast<cuda_tile::PartitionViewType>(getView().getType())) {
1540	    if (pv.getPaddingValue()) {
1541	      return emitOpError("views with padding_value are not supported for "
1542	                         "atomic reductions");
1543	    }
1544	  } else if (auto sv =
1545	                 dyn_cast<cuda_tile::StridedViewType>(getView().getType())) {
1546	    if (sv.getPaddingValue()) {
1547	      return emitOpError("views with padding_value are not supported for "
1548	                         "atomic reductions");
1549	    }
1550	  }
1551	
1552	  auto viewTileType = cast<cuda_tile::TileType>(viewType.getViewTileType());
1553	  Type viewElemType = viewTileType.getElementType();
1554	  Type valueElType = getValue().getType().getElementType();
1555	
1556	  if (viewElemType != valueElType)
1557	    return emitOpError("view element type (")
1558	           << viewElemType << ") must match value element type (" << valueElType
1559	           << ")";
1560	
1561	  // For element-wise atomics, view tile shape must match value shape
1562	  ArrayRef<int64_t> viewShape = viewTileType.getShape();
1563	  ArrayRef<int64_t> valueShape =
1564	      cast<ShapedType>(getValue().getType()).getShape();
1565	
1566	  if (viewShape != valueShape)
1567	    return emitOpError("view tile shape ")
1568	           << viewShape << " must match value shape " << valueShape
1569	           << " for element-wise atomic operations";
1570	
1571	  if (getMode() == AtomicRMWMode::XCHG) {
1572	    return emitOpError("atomic_red_view_tko op cannot use xchg operation");
1573	  }
1574	
1575	  // Check compatibility of RMW mode with element type.
1576	  if (failed(verifyAtomicRMWMode(*this, getMode(), valueElType)))
1577	    return failure();
1578	
1579	  // Memory ordering is restricted to RELAXED only.
1580	  // RELAXED maps to PTX .relaxed.gpu for the atomic reduction to
1581	  // GMEM, while implicit loads are weak (value not returned). This enables TMA
1582	  // REDG (cp.reduce.async.bulk) optimization on Hopper+ GPUs.
1583	  if (getMemoryOrderingSemantics() != MemoryOrderingSemantics::RELAXED) {
1584	    return emitOpError(
1585	        "only 'relaxed' memory ordering is supported for view-based "
1586	        "atomic reductions");
1587	  }
1588	
1589	  // For TMA compatibility (cp.reduce.async.bulk), system scope is not
1590	  // supported. Only tl_blk and device scopes are allowed.
1591	  if (getMemoryScope() == MemoryScope::SYS)
1592	    return emitOpError("memory scope 'sys' is not supported for view-based "
1593	                       "atomic reductions; use 'tl_blk' or 'device' for TMA "
1594	                       "compatibility");
1595	
1596	  // Verify index count matches view tile rank.
1597	  size_t expectedRank = viewTileType.getShape().size();
1598	  if (getIndex().size() != expectedRank) {
1599	    return emitOpError("expected ")
1600	           << expectedRank << " index operand(s) for view with tile rank "
1601	           << expectedRank << ", got " << getIndex().size();
1602	  }
1603	
1604	  // Verify each index is a scalar (rank-0) integer tile.
1605	  for (auto [i, idx] : llvm::enumerate(getIndex())) {
1606	    auto idxTy = cast<cuda_tile::TileType>(idx.getType());
1607	    if (!idxTy.getShape().empty()) {
1608	      return emitOpError("index operand ")
1609	             << i << " must be a scalar tile (rank 0), got shape "
1610	             << idxTy.getShape();
1611	    }
1612	    if (!isa<mlir::IntegerType>(idxTy.getElementType())) {
1613	      return emitOpError("index operand ")
1614	             << i << " must be a scalar integer tile, got element type "
1615	             << idxTy.getElementType();
1616	    }
1617	  }
1618	
1619	  return success();
1620	}
